proof_block:
// `put_spec(old_v, new_v, key, value)` is the open spec
//     `new_v == old_v.insert(key, value)`
// so each side of the conjunction pins `post*_self_.epmap@` to the *same*
// `Map::insert` term `pre_self_.epmap@.insert(src@, value)`. Re-assert each
// consequence under the conjoined hypothesis as a *tautological* implication
// (LHS = both `put_spec`s, RHS = the consequence). This gives z3 a single
// named version of every cross-run map equality so the triggers from the two
// `put_spec` instances line up without re-instantiating `Map::insert`. We
// also lift to `=~=` so `Map`-extensionality is available alongside `==`.
assert((HashMap::put_spec(pre_self_.epmap@, post1_self_.epmap@, src@, value)
        && HashMap::put_spec(pre_self_.epmap@, post2_self_.epmap@, src@, value))
       ==> post1_self_.epmap@ == pre_self_.epmap@.insert(src@, value));

assert((HashMap::put_spec(pre_self_.epmap@, post1_self_.epmap@, src@, value)
        && HashMap::put_spec(pre_self_.epmap@, post2_self_.epmap@, src@, value))
       ==> post2_self_.epmap@ == pre_self_.epmap@.insert(src@, value));

assert((HashMap::put_spec(pre_self_.epmap@, post1_self_.epmap@, src@, value)
        && HashMap::put_spec(pre_self_.epmap@, post2_self_.epmap@, src@, value))
       ==> post1_self_.epmap@ == post2_self_.epmap@);

assert((HashMap::put_spec(pre_self_.epmap@, post1_self_.epmap@, src@, value)
        && HashMap::put_spec(pre_self_.epmap@, post2_self_.epmap@, src@, value))
       ==> post1_self_.epmap@ =~= post2_self_.epmap@);

// `r1` and `r2` are `()`, which Verus knows is a singleton; re-assert the
// unit-equality as a hint so the `r1 == r2` clause inside `det_put_equal`
// fires under the same antecedent.
assert((HashMap::put_spec(pre_self_.epmap@, post1_self_.epmap@, src@, value)
        && HashMap::put_spec(pre_self_.epmap@, post2_self_.epmap@, src@, value))
       ==> r1 == r2);
